async function () {
  try {
    const res = await add_user.run({
      username: username.text,
      password: password.text
    });
    const userId = res.userId;
    storeValue("userId", userId);
    storeValue("password", password);
    const genres = GenreList.selectedOptionValues || [];
    for (let i = 0; i < genres.length; i++) {
      const genreId = genres[i];
      await createPreferredGenre.run({
        userId: userId,
        genreId: genreId
      });
    }
    const characters = CharacterList.selectedOptionValues || [];
    for (let i = 0; i < characters.length; i++) {
      const characterId = characters[i];
      await createPreferredCharacter.run({
        userId: userId,
        characterId: characterId
      });
    }
    const teams = TeamList.selectedOptionValues || [];
    for (let i = 0; i < teams.length; i++) {
      const teamId = teams[i];
      await createPreferredTeam.run({
        userId: userId,
        teamId: teamId
      });
    }
    const publishers = PublisherList.selectedOptionValues || [];
    for (let i = 0; i < publishers.length; i++) {
      const publisherId = publishers[i];
      await createPreferredPublisher.run({
        userId: userId,
        publisherId: publisherId
      });
    }
    showAlert("User and preferences created!", "success");
    getUserPreferredGenres.run();
    getUserPreferredCharacters.run();
    getUserPreferredTeams.run();
    getUserPreferredPublishers.run();
    navigateTo('Log In', {}, 'SAME_WINDOW');
  } catch (err) {
    showAlert("Error: " + err.message, "error");
  }
}

